import { useState, useEffect } from "react";

const COLORS = {
  beige: "#D4C5B9",
  walnut: "#3E2723",
  white: "#FDFCFA",
  green: "#8B9C7C",
};

const rooms = [
  { id: 1, name: "Suite Vista Pineta", desc: "Immersa nella pineta, luce naturale soffusa, letto king, terrazza privata.", price: "€320 / night", tag: "Fuga nella Foresta" },
  { id: 2, name: "Attico Vista Mare", desc: "Vista panoramica sul mare, vetrate dal pavimento al soffitto, bagno di lusso, accesso al tetto.", price: "€580 / night", tag: "Mare & Cielo" },
  { id: 3, name: "Camera Deluxe Moderna", desc: "Loft open-plan con accesso al giardino, interni in legno sostenibile, doccia a pioggia.", price: "€240 / night", tag: "Loft Naturale" },
];


const IMAGES = {
  facade: "data:image/jpeg;base64,",
  pine: "data:image/jpeg;base64,",
  deluxe: "data:image/jpeg;base64,",
  ocean: "data:image/jpeg;base64,",
};

const navLinks = ["Esperienza", "Camere", "Sostenibilità", "Posizione"];

function Nav({ onBook }) {
  const [scrolled, setScrolled] = useState(false);
  useEffect(() => {
    const h = () => setScrolled(window.scrollY > 40);
    window.addEventListener("scroll", h);
    return () => window.removeEventListener("scroll", h);
  }, []);
  return (
    <nav style={{
      position: "fixed", top: 0, left: 0, right: 0, zIndex: 100,
      background: scrolled ? COLORS.white : "transparent",
      borderBottom: scrolled ? `1px solid ${COLORS.beige}` : "none",
      transition: "all 0.4s ease",
      padding: "0 2rem",
    }}>
      <div style={{ maxWidth: 1200, margin: "0 auto", display: "flex", alignItems: "center", justifyContent: "space-between", height: 72 }}>
        <span style={{ fontFamily: "'Syne', sans-serif", fontWeight: 800, fontSize: "1.7rem", letterSpacing: "0.18em", color: scrolled ? COLORS.walnut : COLORS.white }}>FAM</span>
        <div style={{ display: "flex", gap: "2.5rem" }}>
          {navLinks.map(l => (
            <a key={l} href={`#${l.toLowerCase().normalize("NFD").replace(/[̀-ͯ]/g, "")}`} style={{ fontFamily: "'Montserrat', sans-serif", fontSize: "0.78rem", letterSpacing: "0.12em", fontWeight: 600, color: scrolled ? COLORS.walnut : COLORS.white, textDecoration: "none", textTransform: "uppercase", opacity: 0.85 }}>{l}</a>
          ))}
        </div>
        <button onClick={onBook} style={{ background: COLORS.green, color: COLORS.white, border: "none", borderRadius: 2, padding: "0.65rem 1.5rem", fontFamily: "'Montserrat', sans-serif", fontWeight: 700, fontSize: "0.72rem", letterSpacing: "0.12em", textTransform: "uppercase", cursor: "pointer" }}>
          Prenota il Tuo Soggiorno
        </button>
      </div>
    </nav>
  );
}

