function BookingModal({ initial, onClose }) {
  const [step, setPasso] = useState(1); // 1=select, 2=details, 3=confirmed
  const [sel, setSel] = useState(initial?.room || null);
  const [cin, setCin] = useState(initial?.cin || "");
  const [cout, setCout] = useState(initial?.cout || "");
  const [guests, setGuests] = useState(initial?.guests || "2");
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [ref] = useState("FAM-" + Math.random().toString(36).substring(2,8).toUpperCase());

  const inp = (val, set, placeholder, type="text") => (
    <input type={type} value={val} onChange={e => set(e.target.value)} placeholder={placeholder}
      style={{ width: "100%", boxSizing: "border-box", background: COLORS.white, border: `1px solid ${COLORS.beige}`, borderRadius: 2, padding: "0.8rem 1rem", fontFamily: "'Montserrat', sans-serif", fontSize: "0.88rem", color: COLORS.walnut, outline: "none" }} />
  );

  return (
    <div style={{ position: "fixed", inset: 0, zIndex: 200, background: "rgba(62,39,35,0.6)", backdropFilter: "blur(8px)", display: "flex", alignItems: "center", justifyContent: "center", padding: "1rem" }}
      onClick={e => e.target === e.currentTarget && onClose()}>
      <div style={{ background: COLORS.white, borderRadius: 4, maxWidth: 560, width: "100%", maxHeight: "90vh", overflowY: "auto", boxShadow: "0 32px 80px rgba(62,39,35,0.25)" }}>
        {/* Header */}
        <div style={{ padding: "2rem 2rem 1.5rem", borderBottom: `1px solid ${COLORS.beige}`, display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
          <div>
            <p style={{ fontFamily: "'Montserrat', sans-serif", fontSize: "0.65rem", letterSpacing: "0.25em", color: COLORS.green, textTransform: "uppercase", fontWeight: 700, margin: "0 0 0.3rem" }}>
              {step===3 ? "Prenotazione Confermata" : `Passo ${step} di 2`}
            </p>
            <h3 style={{ fontFamily: "'Syne', sans-serif", fontWeight: 800, fontSize: "1.5rem", color: COLORS.walnut, margin: 0 }}>
              {step===1 ? "Scegli la Tua Camera" : step===2 ? "I Tuoi Dati" : "A Presto al FAM"}
            </h3>
          </div>
          <button onClick={onClose} style={{ background: "none", border: "none", fontSize: "1.5rem", color: COLORS.beige, cursor: "pointer", lineHeight: 1 }}>✕</button>
        </div>

        <div style={{ padding: "2rem" }}>
          {step === 1 && (
            <div style={{ display: "flex", flexDirection: "column", gap: "1rem" }}>
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: "0.8rem", marginBottom: "0.5rem" }}>
                {[
                  { label: "Check-in", val: cin, set: setCin, type: "date" },
                  { label: "Check-out", val: cout, set: setCout, type: "date" },
                  { label: "Ospiti", val: guests, set: setGuests, type: "select" },
                ].map(f => (
                  <div key={f.label}>
                    <label style={{ fontFamily: "'Montserrat', sans-serif", fontSize: "0.65rem", letterSpacing: "0.18em", color: COLORS.green, textTransform: "uppercase", fontWeight: 700, display: "block", marginBottom: 6 }}>{f.label}</label>
                    {f.type === "select" ? (
                      <select value={f.val} onChange={e => f.set(e.target.value)} style={{ width: "100%", background: COLORS.white, border: `1px solid ${COLORS.beige}`, borderRadius: 2, padding: "0.75rem 0.6rem", fontFamily: "'Montserrat', sans-serif", fontSize: "0.85rem", color: COLORS.walnut, outline: "none" }}>
                        {[1,2,3,4].map(n => <option key={n} value={n}>{n} {n===1?"Ospite":"Ospiti"}</option>)}
                      </select>
                    ) : (
                      <input type={f.type} value={f.val} onChange={e => f.set(e.target.value)} style={{ width: "100%", boxSizing: "border-box", background: COLORS.white, border: `1px solid ${COLORS.beige}`, borderRadius: 2, padding: "0.75rem 0.6rem", fontFamily: "'Montserrat', sans-serif", fontSize: "0.85rem", color: COLORS.walnut, outline: "none" }} />
                    )}
                  </div>
                ))}
              </div>
              {rooms.map(r => (
                <div key={r.id} onClick={() => setSel(r)} style={{ padding: "1.2rem", border: `2px solid ${sel?.id===r.id ? COLORS.green : COLORS.beige}`, borderRadius: 2, cursor: "pointer", background: sel?.id===r.id ? "rgba(139,156,124,0.06)" : COLORS.white, transition: "all 0.2s" }}>
                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
                    <div>
                      <span style={{ fontFamily: "'Syne', sans-serif", fontWeight: 700, fontSize: "0.98rem", color: COLORS.walnut }}>{r.name}</span>
                      <span style={{ marginLeft: "0.7rem", background: COLORS.beige, color: COLORS.walnut, fontSize: "0.6rem", fontFamily: "'Montserrat', sans-serif", fontWeight: 600, letterSpacing: "0.1em", textTransform: "uppercase", padding: "0.15rem 0.5rem", borderRadius: 1 }}>{r.tag}</span>
                    </div>
                    <span style={{ fontFamily: "'Syne', sans-serif", fontWeight: 800, fontSize: "0.9rem", color: COLORS.green, whiteSpace: "nowrap" }}>{r.price}</span>
                  </div>
                  <p style={{ fontFamily: "'Montserrat', sans-serif", fontSize: "0.8rem", color: "#9a8a82", margin: "0.4rem 0 0", lineHeight: 1.6 }}>{r.desc}</p>
                </div>
              ))}
              <button onClick={() => sel && setPasso(2)} style={{ marginTop: "0.5rem", background: sel ? COLORS.green : COLORS.beige, color: COLORS.white, border: "none", borderRadius: 2, padding: "1rem", fontFamily: "'Montserrat', sans-serif", fontWeight: 700, fontSize: "0.75rem", letterSpacing: "0.14em", textTransform: "uppercase", cursor: sel ? "pointer" : "not-allowed", transition: "background 0.2s" }}>
                Continua →
              </button>
            </div>
          )}

          {step === 2 && (
            <div style={{ display: "flex", flexDirection: "column", gap: "1.2rem" }}>
              {/* Summary */}
              <div style={{ background: COLORS.beige, borderRadius: 2, padding: "1.2rem", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                <div>
                  <p style={{ fontFamily: "'Montserrat', sans-serif", fontSize: "0.65rem", letterSpacing: "0.18em", color: COLORS.green, textTransform: "uppercase", fontWeight: 700, margin: "0 0 0.3rem" }}>Camera Selezionata</p>
                  <p style={{ fontFamily: "'Syne', sans-serif", fontWeight: 700, fontSize: "1rem", color: COLORS.walnut, margin: 0 }}>{sel?.name}</p>
                </div>
                <span style={{ fontFamily: "'Syne', sans-serif", fontWeight: 800, color: COLORS.green }}>{sel?.price}</span>
              </div>
              {cin && cout && <div style={{ background: COLORS.white, border: `1px solid ${COLORS.beige}`, borderRadius: 2, padding: "0.8rem 1.2rem", display: "flex", justifyContent: "space-between" }}>
                <span style={{ fontFamily: "'Montserrat', sans-serif", fontSize: "0.8rem", color: "#9a8a82" }}>Check-in</span>
                <span style={{ fontFamily: "'Montserrat', sans-serif", fontSize: "0.8rem", fontWeight: 600, color: COLORS.walnut }}>{cin}</span>
                <span style={{ fontFamily: "'Montserrat', sans-serif", fontSize: "0.8rem", color: "#9a8a82" }}>Check-out</span>
                <span style={{ fontFamily: "'Montserrat', sans-serif", fontSize: "0.8rem", fontWeight: 600, color: COLORS.walnut }}>{cout}</span>
              </div>}
              <div>
                <label style={{ fontFamily: "'Montserrat', sans-serif", fontSize: "0.65rem", letterSpacing: "0.18em", color: COLORS.green, textTransform: "uppercase", fontWeight: 700, display: "block", marginBottom: 8 }}>Nome Completo</label>
                {inp(name, setName, "es. Marco Rossi")}
              </div>
              <div>
                <label style={{ fontFamily: "'Montserrat', sans-serif", fontSize: "0.65rem", letterSpacing: "0.18em", color: COLORS.green, textTransform: "uppercase", fontWeight: 700, display: "block", marginBottom: 8 }}>Indirizzo Email</label>
                {inp(email, setEmail, "marco@example.com", "email")}
              </div>
              <div style={{ display: "flex", gap: "0.8rem", marginTop: "0.5rem" }}>
                <button onClick={() => setPasso(1)} style={{ flex: 1, background: "none", border: `1px solid ${COLORS.beige}`, color: COLORS.walnut, borderRadius: 2, padding: "0.9rem", fontFamily: "'Montserrat', sans-serif", fontWeight: 600, fontSize: "0.72rem", letterSpacing: "0.12em", textTransform: "uppercase", cursor: "pointer" }}>← Indietro</button>
                <button onClick={() => name && email && setPasso(3)} style={{ flex: 2, background: name && email ? COLORS.walnut : COLORS.beige, color: COLORS.white, border: "none", borderRadius: 2, padding: "0.9rem", fontFamily: "'Montserrat', sans-serif", fontWeight: 700, fontSize: "0.72rem", letterSpacing: "0.14em", textTransform: "uppercase", cursor: name && email ? "pointer" : "not-allowed", transition: "background 0.2s" }}>
                  Conferma Prenotazione
                </button>
              </div>
            </div>
          )}

          {step === 3 && (
            <div style={{ textAlign: "center", padding: "1.5rem 0" }}>
              <div style={{ width: 72, height: 72, borderRadius: "50%", background: "rgba(139,156,124,0.12)", border: `2px solid ${COLORS.green}`, display: "flex", alignItems: "center", justifyContent: "center", margin: "0 auto 1.8rem", fontSize: "2rem" }}>✓</div>
              <p style={{ fontFamily: "'Montserrat', sans-serif", fontSize: "0.7rem", letterSpacing: "0.25em", color: COLORS.green, textTransform: "uppercase", fontWeight: 700, marginBottom: "0.5rem" }}>Riferimento Prenotazione</p>
              <p style={{ fontFamily: "'Syne', sans-serif", fontWeight: 800, fontSize: "1.6rem", color: COLORS.walnut, letterSpacing: "0.2em", margin: "0 0 2rem" }}>{ref}</p>
              <div style={{ background: COLORS.beige, borderRadius: 2, padding: "1.5rem", textAlign: "left", display: "flex", flexDirection: "column", gap: "0.9rem", marginBottom: "2rem" }}>
                {[
                  ["Ospite", name],
                  ["Email", email],
                  ["Camera", sel?.name],
                  ...(cin ? [["Check-in", cin]] : []),
                  ...(cout ? [["Check-out", cout]] : []),
                  ["Ospiti", `${guests} ${Number(guests)===1?"Persona":"Persone"}`],
                  ["Tariffa", sel?.price],
                ].map(([k, v]) => (
                  <div key={k} style={{ display: "flex", justifyContent: "space-between" }}>
                    <span style={{ fontFamily: "'Montserrat', sans-serif", fontSize: "0.72rem", letterSpacing: "0.1em", textTransform: "uppercase", color: "#9a8a82", fontWeight: 600 }}>{k}</span>
                    <span style={{ fontFamily: "'Montserrat', sans-serif", fontSize: "0.88rem", color: COLORS.walnut, fontWeight: 600 }}>{v}</span>
                  </div>
                ))}
              </div>
              <p style={{ fontFamily: "'Montserrat', sans-serif", fontSize: "0.82rem", color: "#9a8a82", lineHeight: 1.7, marginBottom: "1.8rem" }}>
                Una conferma è stata inviata a <strong style={{ color: COLORS.walnut }}>{email}</strong>. Non vediamo l'ora di accogliervi al FAM.
              </p>
              <button onClick={onClose} style={{ background: COLORS.green, color: COLORS.white, border: "none", borderRadius: 2, padding: "0.9rem 2.5rem", fontFamily: "'Montserrat', sans-serif", fontWeight: 700, fontSize: "0.72rem", letterSpacing: "0.14em", textTransform: "uppercase", cursor: "pointer" }}>
                Torna al FAM Hotel
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

export default function App() {
  const [modal, setModal] = useState(null);

  useEffect(() => {
    const link = document.createElement("link");
    link.rel = "stylesheet";
    link.href = "https://fonts.googleapis.com/css2?family=Syne:wght@700;800&family=Montserrat:wght@400;500;600;700&display=swap";
    document.head.appendChild(link);
  }, []);

  return (
    <div style={{ background: COLORS.white, overflowX: "hidden" }}>
      <Nav onBook={() => setModal({})} />
      <Hero onSearch={(d) => setModal(d)} />
      <Features />
      <Rooms onBook={(r) => setModal({ room: r })} />
      <SustainabilityBar />
      <Footer />
      {modal !== null && <BookingModal initial={modal} onClose={() => setModal(null)} />}
    </div>
  );
}
